export function canTransitionTo(from: OrderStatus, to: OrderStatus): boolean {
  const transitions: Record<OrderStatus, OrderStatus[]> = {
    [OrderStatus.PENDING]: [OrderStatus.IN_PROGRESS, OrderStatus.VOIDED],
    [OrderStatus.IN_PROGRESS]: [OrderStatus.DISPATCHED, OrderStatus.VOIDED],
    [OrderStatus.DISPATCHED]: [OrderStatus.DELIVERED, OrderStatus.VOIDED],
    [OrderStatus.DELIVERED]: [],
    [OrderStatus.VOIDED]: [],
  };
  return transitions[from]?.includes(to) ?? false;
}

